## Setup ----
example_path <- testthat::test_path(
  "..",
  "..",
  "inst",
  "examples",
  "shared_module_graph.R"
)

## IO correctness ----
test_that("module graph specs represent shared submodules", {
  #' @description Test that graph specs store modules once and links from multiple parents.
  shared_growth <- module(
    "growth.shared",
    ewaa_growth(ages = 1:4, weights = c(0.2, 0.5, 0.9, 1.1))
  )
  shared_selectivity <- module(
    "selectivity.shared",
    logistic_selectivity(a50 = estimate(3), slope = constant(1.1))
  )
  recruitment_a <- module(
    "recruitment.a",
    beverton_holt(
      log_rzero = estimate(log(1000)),
      steepness = constant(0.75)
    )
  )
  recruitment_b <- module(
    "recruitment.b",
    beverton_holt(
      log_rzero = estimate(log(800)),
      steepness = constant(0.72)
    )
  )
  maturity_a <- module("maturity.a", logistic_maturity(3, 1.2))
  maturity_b <- module("maturity.b", logistic_maturity(4, 1.1))
  population_a <- module(
    "population.a",
    population(
      name = "stock_a",
      ages = 1:4,
      years = 2020:2022,
      growth = ref("growth.shared"),
      maturity = ref("maturity.a"),
      recruitment = ref("recruitment.a")
    )
  )
  population_b <- module(
    "population.b",
    population(
      name = "stock_b",
      ages = 1:4,
      years = 2020:2022,
      growth = ref("growth.shared"),
      maturity = ref("maturity.b"),
      recruitment = ref("recruitment.b")
    )
  )
  fleet_a <- module(
    "fleet.a",
    fleet(
      name = "fishery_a",
      selectivity = ref("selectivity.shared"),
      fishing_mortality = estimate(rep(log(0.1), 3))
    )
  )
  fleet_b <- module(
    "fleet.b",
    fleet(
      name = "fishery_b",
      selectivity = ref("selectivity.shared"),
      fishing_mortality = estimate(rep(log(0.08), 3))
    )
  )

  graph <- as_model_graph(list(
    shared_growth,
    shared_selectivity,
    recruitment_a,
    recruitment_b,
    maturity_a,
    maturity_b,
    population_a,
    population_b,
    fleet_a,
    fleet_b
  ))

  expect_s3_class(graph, "fims_model_graph")
  expect_s3_class(graph[["modules"]], "data.frame")
  expect_s3_class(graph[["links"]], "data.frame")
  expect_equal(nrow(graph[["modules"]]), 10L)
  expect_named(graph[["modules"]], c("id", "type", "name", "spec"))
  expect_named(graph[["links"]], c("from", "role", "to"))

  growth_links <- graph[["links"]][graph[["links"]][["to"]] == "growth.shared", ]
  expect_equal(nrow(growth_links), 2L)
  expect_equal(sort(growth_links[["from"]]), c("population.a", "population.b"))
  expect_true(all(growth_links[["role"]] == "growth"))

  selectivity_links <- graph[["links"]][
    graph[["links"]][["to"]] == "selectivity.shared",
  ]
  expect_equal(nrow(selectivity_links), 2L)
  expect_equal(sort(selectivity_links[["from"]]), c("fleet.a", "fleet.b"))
  expect_true(all(selectivity_links[["role"]] == "selectivity"))
})

test_that("model graphs round trip through tibbles", {
  #' @description Test that model graphs can be converted to tibbles and rebuilt from those tibbles.
  shared_growth <- module("growth.shared", ewaa_growth(1:4, 1:4))
  recruitment <- module(
    "recruitment.a",
    beverton_holt(estimate(log(1000)), constant(0.75))
  )
  maturity <- module("maturity.a", logistic_maturity(3, 1))
  population_module <- module(
    "population.a",
    population(
      name = "stock_a",
      ages = 1:4,
      years = 2020:2022,
      growth = ref("growth.shared"),
      maturity = ref("maturity.a"),
      recruitment = ref("recruitment.a")
    )
  )
  graph <- as_model_graph(list(
    shared_growth,
    recruitment,
    maturity,
    population_module
  ))

  tibbles <- model_graph_tibbles(graph)
  expect_s3_class(tibbles[["modules"]], "data.frame")
  expect_s3_class(tibbles[["links"]], "data.frame")

  rebuilt_graph <- model_graph_from_tibbles(
    modules = tibbles[["modules"]],
    links = tibbles[["links"]]
  )
  expect_s3_class(rebuilt_graph, "fims_model_graph")
  expect_equal(rebuilt_graph[["modules"]], graph[["modules"]])
  expect_equal(rebuilt_graph[["links"]], graph[["links"]])
})

test_that("shared module graph example runs", {
  #' @description Test that the shared module graph example creates shared growth and selectivity links.
  example_env <- new.env(parent = globalenv())

  expect_no_error(capture.output(sys.source(example_path, envir = example_env)))
  expect_s3_class(example_env$graph, "fims_model_graph")

  links <- example_env$graph[["links"]]
  modules <- example_env$graph[["modules"]]
  expect_s3_class(example_env$tibbles[["modules"]], "data.frame")
  expect_s3_class(example_env$tibbles[["links"]], "data.frame")
  expect_s3_class(example_env$rebuilt_graph, "fims_model_graph")
  expect_equal(example_env$rebuilt_graph[["links"]], example_env$graph[["links"]])

  growth_links <- links[links[["to"]] == "growth.shared", ]
  selectivity_links <- links[links[["to"]] == "selectivity.shared", ]

  expect_equal(nrow(growth_links), 2L)
  expect_equal(nrow(selectivity_links), 2L)
  expect_true(all(c("landings", "index") %in% modules[["type"]]))
  expect_equal(sum(modules[["type"]] == "landings"), 2L)
  expect_equal(sum(modules[["type"]] == "index"), 2L)
})

## Edge handling ----
test_that("model graph specs validate module ids and references", {
  #' @description Test that graph specs reject bad ids, duplicated ids, and missing references.
  expect_error(module("", ewaa_growth(1:3, 1:3)), regexp = "`id`")
  expect_error(ref(""), regexp = "`id`")
  expect_error(module("bad", "not a spec"), regexp = "`spec`")

  growth <- module("growth.shared", ewaa_growth(1:3, 1:3))
  duplicate_growth <- module("growth.shared", ewaa_growth(1:3, 1:3))
  expect_error(
    as_model_graph(list(growth, duplicate_growth)),
    regexp = "Module ids must be unique"
  )

  population_with_missing_ref <- module(
    "population.a",
    population(
      name = "stock_a",
      ages = 1:3,
      years = 2020:2022,
      growth = ref("growth.missing"),
      maturity = logistic_maturity(3, 1),
      recruitment = beverton_holt(estimate(log(1000)), constant(0.75))
    )
  )
  expect_error(
    as_model_graph(list(population_with_missing_ref)),
    regexp = "References must point to existing module ids"
  )

  graph <- as_model_graph(list(
    growth,
    module(
      "population.a",
      population(
        name = "stock_a",
        ages = 1:3,
        years = 2020:2022,
        growth = ref("growth.shared"),
        maturity = logistic_maturity(3, 1),
        recruitment = beverton_holt(estimate(log(1000)), constant(0.75))
      )
    )
  ))
  bad_links <- graph[["links"]]
  bad_links[["to"]][1] <- "growth.other"
  expect_error(
    model_graph_from_tibbles(graph[["modules"]], bad_links),
    regexp = "`links` must match the references stored in the module specs"
  )
})
